                              <button onClick={() => handleDelete('RECURRING', rule.id)} className="p-2 text-gray-500 hover:text-red-400 bg-gray-800 hover:bg-gray-700 rounded-lg active:scale-90 transition-transform">
                                  <Trash2 size={18} />
                              </button>
