                             style={{
                                backgroundImage: `linear-gradient(45deg, #8A1538 25%, transparent 25%), linear-gradient(-45deg, #8A1538 25%, transparent 25%)`,
                                backgroundSize: '10px 10px',
                                backgroundRepeat: 'repeat-x'
