                            </h2>
                            <p className="text-[10px] text-gold-500/70 uppercase tracking-[0.2em] mt-2 font-semibold">
                                {mode === 'login' ? 'Access your Vault' : 'Secure your Future'}
                            </p>
                        </div>

                        {/* Error Message */}
                        {error && (
                            <motion.div 
                                initial={{ opacity: 0, height: 0 }} 
                                animate={{ opacity: 1, height: 'auto' }}
